    private val userProfileRepository: UserProfileRepository,
) {
    // 첫 조회만 DB 접근, 이후 Redis에서 반환
    @Cacheable(
        cacheNames = [CacheNames.USER_PROFILE],
        key = "#userId",
        unless = "#result == null",
    )
    fun getProfile(userId: String): UserProfileEntity {
        return userProfileRepository.findByUserId(userId)
            ?: throw NoSuchElementException("프로필 없음: $userId")
    }

    // 프로필 수정 시 캐시 무효화
    @CacheEvict(
        cacheNames = [CacheNames.USER_PROFILE],
        key = "#command.userId",
    )
    @Transactional
    fun updateProfile(command: UpdateProfileCommand): UserProfileEntity {
        val profile = userProfileRepository.findByUserId(command.userId)
            ?: throw NoSuchElementException("프로필 없음: ${command.userId}")
        // 변경 로직
        return userProfileRepository.save(profile)
    }
}
```

예상 개선: 프로필 조회 응답 시간 **50ms -> 2ms (96% 감소)**, DB 쿼리 수 **최대 95% 감소**

