#### 3-5. Before / After: 팔로우 카운트 캐시 (집계 쿼리 최적화)

N+1의 대표 패턴인 목록에서의 집계 조회를 처리합니다.

```kotlin
// Before: 유저 목록 20명 조회 시 20번의 COUNT 쿼리 발생
@Service
class FollowService(private val followRepository: FollowRepository) {
    fun getFollowerCount(userId: String): Long {
        return followRepository.countByTargetUserId(userId) // 매번 COUNT(*) 실행
    }
}

// After: Redis에 카운터로 저장, 팔로우/언팔로우 시 증감
@Service
class FollowService(
    private val followRepository: FollowRepository,
    private val redisTemplate: RedisTemplate<String, Any>,
) {
    private fun followerCountKey(userId: String) = "follow:count:follower:$userId"
    private fun followingCountKey(userId: String) = "follow:count:following:$userId"

    fun getFollowerCount(userId: String): Long {
        val key = followerCountKey(userId)
        // 캐시 미스 시 DB에서 읽어 캐시에 저장
        val cached = redisTemplate.opsForValue().get(key)
        if (cached != null) return cached.toString().toLong()

        val count = followRepository.countByTargetUserId(userId)
        redisTemplate.opsForValue().set(key, count, Duration.ofMinutes(1))
        return count
    }

    @Transactional
    fun follow(followerId: String, targetUserId: String) {
        followRepository.save(FollowEntity(followerId = followerId, targetUserId = targetUserId))
        // 카운터 즉시 증감 (캐시와 DB 동기화)
        redisTemplate.opsForValue().increment(followerCountKey(targetUserId))
        redisTemplate.opsForValue().increment(followingCountKey(followerId))
    }

    @Transactional
    fun unfollow(followerId: String, targetUserId: String) {
        followRepository.deleteByFollowerIdAndTargetUserId(followerId, targetUserId)
        redisTemplate.opsForValue().decrement(followerCountKey(targetUserId))
        redisTemplate.opsForValue().decrement(followingCountKey(followerId))
    }
}
```

예상 개선: 유저 목록 20명 조회 시 팔로워 카운트 쿼리 **20회 -> 0회**, 집계 응답 **30ms -> 0.5ms**

